@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (loading)
{
    <div class="text-center py-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger">@errorMessage</div>
}
else
{
    <BoardStats Tasks="allTasks" />
    <BoardSearchBar OnSearchChanged="HandleSearch" />

    <div class="row g-3">
        <KanbanColumn ColumnName="To Do"
                      Tasks="GetTasksForColumn(\"To Do\")"
                      CanMoveLeft="false"
                      CanMoveRight="true"
                      OnMoveRight="task => MoveTask(task, \"In Progress\")"
                      OnTaskCreated="HandleTaskCreated" />

        <KanbanColumn ColumnName="In Progress"
                      Tasks="GetTasksForColumn(\"In Progress\")"
                      CanMoveLeft="true"
                      CanMoveRight="true"
                      OnMoveLeft="task => MoveTask(task, \"To Do\")"
                      OnMoveRight="task => MoveTask(task, \"Done\")"
                      OnTaskCreated="HandleTaskCreated" />

        <KanbanColumn ColumnName="Done"
                      Tasks="GetTasksForColumn(\"Done\")"
                      CanMoveLeft="true"
                      CanMoveRight="false"
                      OnMoveLeft="task => MoveTask(task, \"In Progress\")"
                      OnTaskCreated="HandleTaskCreated" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchText = "";
    private bool loading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            loading = false;
        }
    }

    private List<TaskItem> GetTasksForColumn(string status)
    {
        var tasks = allTasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchText))
        {
            tasks = tasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
        }
        return tasks.ToList();
    }

    private void HandleSearch(string text)
    {
        searchText = text;
    }

    private async Task MoveTask(TaskItem task, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            var index = allTasks.FindIndex(t => t.Id == task.Id);
            if (index >= 0)
            {
                allTasks[index] = task with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task HandleTaskCreated(TaskItem task)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(task.Title, task.Assignee, task.Priority, task.DueDate);
            allTasks.Add(created);
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
    }
}

